909	    /// # t2.join().unwrap(); // join thread to avoid https://github.com/rust-lang/miri/issues/1371
910	    /// ```
911	    pub fn select_timeout(
912	        &mut self,
913	        timeout: Duration,
914	    ) -> Result<SelectedOperation<'a>, SelectTimeoutError> {
915	        select_timeout(&mut self.handles, timeout, self.biased)
916	    }
